import{_ as a,n as i,p as l,Y as e}from"./chunks/framework.KP8KjELV.js";const _=JSON.parse('{"title":"Vim 备忘","description":"","frontmatter":{},"headers":[],"relativePath":"Stack/Vim/Vim命令大全.md","filePath":"Stack/Vim/Vim命令大全.md","lastUpdated":1703840066000}'),o={name:"Stack/Vim/Vim命令大全.md"},r=e('<h1 id="vim-备忘" tabindex="-1">Vim 备忘 <a class="header-anchor" href="#vim-备忘" aria-label="Permalink to &quot;Vim 备忘&quot;">​</a></h1><h2 id="_1-vim介绍" tabindex="-1">1.vim介绍 <a class="header-anchor" href="#_1-vim介绍" aria-label="Permalink to &quot;1.vim介绍&quot;">​</a></h2><h3 id="vim-常用的有四个模式" tabindex="-1">VIM 常用的有四个模式，： <a class="header-anchor" href="#vim-常用的有四个模式" aria-label="Permalink to &quot;VIM 常用的有四个模式，：&quot;">​</a></h3><ul><li>正常模式 (Normal-mode)</li><li>插入模式 (Insert-mode)</li><li>命令模式 (Command-mode)</li><li>可视模式 (Visual-mode)</li></ul><p><strong>模式间切换方法</strong>： （1）命令模式下，输入<code>:</code>后，进入末行模式 （2）末行模式下，按<code>esc</code>慢退、按两次<code>esc</code>快退、或者删除所有命令，可以回到命令模式 （3）命令模式下，按下<code>i</code>、<code>a</code>等键，可以进入编辑模式 （4）编辑模式下，按下<code>esc</code>，可以回到命令模式</p><h2 id="_1-助记符" tabindex="-1">1 助记符 <a class="header-anchor" href="#_1-助记符" aria-label="Permalink to &quot;1 助记符&quot;">​</a></h2><p>vim 上的所有定义的快捷键都是有一定的意义的，在这里我先把常用的一些列出来。</p><h3 id="_1-1-正则表达式相关" tabindex="-1">1.1 正则表达式相关 <a class="header-anchor" href="#_1-1-正则表达式相关" aria-label="Permalink to &quot;1.1 正则表达式相关&quot;">​</a></h3><ul><li>$ ： 移动光标到行尾</li><li>^ : 移动光标到当前行的第一个字母位置。</li></ul><h3 id="_1-2-移动类-motion" tabindex="-1">1.2 移动类（motion） <a class="header-anchor" href="#_1-2-移动类-motion" aria-label="Permalink to &quot;1.2 移动类（motion）&quot;">​</a></h3><p>h（左）、l（右）、j（上）、k（下）、f（front）、b（back）、u（up）</p><h3 id="_1-3-操作类-operator" tabindex="-1">1.3 操作类（operator） <a class="header-anchor" href="#_1-3-操作类-operator" aria-label="Permalink to &quot;1.3 操作类（operator）&quot;">​</a></h3><p>d（delete）、i（insert）、a（append）、c（change）、y（copy）、p（paste）</p><h3 id="_1-4-一般的缩写" tabindex="-1">1.4 一般的缩写 <a class="header-anchor" href="#_1-4-一般的缩写" aria-label="Permalink to &quot;1.4 一般的缩写&quot;">​</a></h3><p>w（word）、s（sentence）</p><h2 id="_2-理解-vim-中三种常用模式" tabindex="-1">2 理解 vim 中三种常用模式 <a class="header-anchor" href="#_2-理解-vim-中三种常用模式" aria-label="Permalink to &quot;2 理解 vim 中三种常用模式&quot;">​</a></h2><p>vim 里面有好几种模式，但是因为我这里介绍的是在目前的编辑器里面装 插件，所以像命令模式这种用来保存文件、退出文件的就不介绍了。</p><ol><li>Nomal mode（默认模式，因为使用该模式场景最多，所有定为默认模式）。</li><li>Insert mode （插入模式--少用，用了它 vim 就成 「哑巴」了）。</li><li>Visual mode（可视模式，取名叫光标模式或者选择模式可能还比较好理解）</li></ol><h2 id="_3-教程篇" tabindex="-1">3 教程篇 <a class="header-anchor" href="#_3-教程篇" aria-label="Permalink to &quot;3 教程篇&quot;">​</a></h2><p>当我们记住上面的助记符之后，我们就可以像写英文短语一样操作了。</p><blockquote><p>vim 快捷键语法：[operator][count][motion]，例如 删两个单词就是 d2w，operator 和 motion 我已经在前面给出来一些了。</p></blockquote><h3 id="_3-1-移动光标" tabindex="-1">3.1 移动光标 <a class="header-anchor" href="#_3-1-移动光标" aria-label="Permalink to &quot;3.1 移动光标&quot;">​</a></h3><h4 id="_3-1-1-最基本的-h、j、k、l" tabindex="-1">3.1.1 最基本的 h、j、k、l <a class="header-anchor" href="#_3-1-1-最基本的-h、j、k、l" aria-label="Permalink to &quot;3.1.1 最基本的 h、j、k、l&quot;">​</a></h4><p>最基本的上下左右移动（跟键盘上下左右的键盘效果相同，但是往往方向键在键盘的右下方，离主键盘区较远，这个也相对比较有优势）：</p><ul><li>h：光标向左移动</li><li>j：光标向下移动</li><li>k：光标向上移动</li><li>l：光标向右移动</li></ul><p>移动属于 motion，所以在前面加上「count」就可以移动多行了，比如向上移动 10 行，就可以 10k。往往编辑器会有行号，定位需要做个加减法，如果采用的是相对行号，用这个就比较方便。</p><h4 id="_3-1-2-快速移动" tabindex="-1">3.1.2 快速移动 <a class="header-anchor" href="#_3-1-2-快速移动" aria-label="Permalink to &quot;3.1.2 快速移动&quot;">​</a></h4><p>w：光标往前移动一个词 b：光标向后移动一个词 0：移动光标到当前行首 ^：移动光标到当前行的第一个字母位置(注意与 0 的区别) $：移动光标到行尾 fx：移动光标到当前行的下一个 x 处（x为任意字母） tx：和上面一个命令类似，移动到 x 的左边一个位置 )：移动光标到下一个句子 ( ：移动光标到上一个句子 {：移动光标到上一段 }：移动光标到下一段</p><h4 id="_3-1-3-快速定位" tabindex="-1">3.1.3 快速定位 <a class="header-anchor" href="#_3-1-3-快速定位" aria-label="Permalink to &quot;3.1.3 快速定位&quot;">​</a></h4><p>在刚才介绍了通过相对行号来进行移动到行的光标，还有采用绝对定位来移动的。那就是 gg。 语法： [num]gg</p><ul><li>2gg : 光标移动到第 2 行</li><li>gg： 光标移动到文件首部</li><li>G：移动到文件胃部</li><li>H：移动到屏幕上面</li><li>M：移动到屏幕中间</li><li>L：移动到屏幕下面</li></ul><p>书签功能：这个功能也是很方便，很少有编辑器有的功能，单独列出来讲，强烈推荐。</p><ul><li>m：给当前行加入书签，x 为任意字母（m 是 mark ）</li><li>` ： 单引号加上刚才 m 之后的字母，就会调整到刚才标记的那一行</li></ul><h3 id="_3-1-3-屏幕滚动" tabindex="-1">3.1.3 屏幕滚动 <a class="header-anchor" href="#_3-1-3-屏幕滚动" aria-label="Permalink to &quot;3.1.3 屏幕滚动&quot;">​</a></h3><ul><li>Ctrl + b：向上移动一屏（Foward首字母小写）</li><li>Ctrl + f：向下移动一屏（Backward首字母小写）</li><li>Ctrl + d：向下滚动半屏内容（Down首字母小写）</li><li>Ctrl + u：向上滚动半屏内容（Up首字母小写）</li></ul><h3 id="_3-2-剪切、复制、粘贴" tabindex="-1">3.2 剪切、复制、粘贴 <a class="header-anchor" href="#_3-2-剪切、复制、粘贴" aria-label="Permalink to &quot;3.2 剪切、复制、粘贴&quot;">​</a></h3><ul><li>d[n]w：剪切后面 n 个单词的内容，dw 是剪切当前单词</li><li>[n]dd：剪切n行的内容, dd 为剪切当前行</li><li>D：剪切光标后到行尾的内容</li><li>yy/Y：复制当前行的内容</li><li>p：粘贴到光标后</li><li>P：粘贴到光标前</li></ul><p>在 normal 模式下是没有删除操作的，d 这种删除也是剪切。</p><blockquote><p>以上全是 normal 模式</p></blockquote><h3 id="_3-3-编辑模式" tabindex="-1">3.3 编辑模式 <a class="header-anchor" href="#_3-3-编辑模式" aria-label="Permalink to &quot;3.3 编辑模式&quot;">​</a></h3><p>在前面也说了，进入编辑模式也就变成了「哑巴」vim 了，就跟一般的编辑器没什么区别了。很多人就知道用 i 可以进入，还有很多命令可以让你聪明的进入。</p><ul><li>i：在光标处插入（insert首字母小写）</li><li>I：在行首插入（insert首字母大写）</li><li>a：在光标处后一个字符插入（append首字母小写）</li><li>A：在行尾插入（append首字母大写）</li><li>o：在上一行插入</li><li>O：在下一行插入</li><li>s：清除当前字符并进入插入模式</li><li>cc/S：清除当前行并进入插入模式</li><li>cw: 清除当前单词并进入插入模式</li></ul><h3 id="_3-4-可视模式" tabindex="-1">3.4 可视模式 <a class="header-anchor" href="#_3-4-可视模式" aria-label="Permalink to &quot;3.4 可视模式&quot;">​</a></h3><p>要是前面都学会了，可视模式就比较简单了，而且你将会经常用到这个模式。我会把这个模式称做「选择模式」，接下来我们就来探索一下是如果选择的。</p><p>其实也就两个关键的点：v（字符选择）、V（行选择）</p><h4 id="_3-4-1-v-小写-v" tabindex="-1">3.4.1 v（小写 v） <a class="header-anchor" href="#_3-4-1-v-小写-v" aria-label="Permalink to &quot;3.4.1 v（小写 v）&quot;">​</a></h4><p>在 normal 模式下，按一下 v，然后可以按 l，重复按 l，你会发现右边的在一直被选中（高亮的部分）。同样的操作，按了 v，然后再练习一下按 h、j、k。</p><p>选中的目的是什么呢？就是为了进行一些编辑操作，比如删除 d (实质是剪切)、复制 y。</p><blockquote><p>小提示，常常选中之后用 c 也是比较好的选择哦，剪切并进入插入模式。</p></blockquote><h4 id="_3-4-2-v-大写-v" tabindex="-1">3.4.2 V（大写 V） <a class="header-anchor" href="#_3-4-2-v-大写-v" aria-label="Permalink to &quot;3.4.2 V（大写 V）&quot;">​</a></h4><p>V 就是选中行，也很简单。按了 V 之后，然后按 j、k，就可以上下选择行了，然后一次性删除 d、复制 y，就比较方便。</p><h3 id="_3-5-组合操作" tabindex="-1">3.5 组合操作 <a class="header-anchor" href="#_3-5-组合操作" aria-label="Permalink to &quot;3.5 组合操作&quot;">​</a></h3><p>这个功能就比较强悍了，很适用，强烈推荐。 先来记公式：operator + i|a + scope</p><blockquote><p>operator 就是我们前面提到的插入（c）、剪切（d）、复制（y）以及选择（v），i 表示 scope 范围内，a 表示包含 scope 标签，scope 就是操作的范围了。</p></blockquote><p>实例： 以下如果将 i 换成 a，则会将符号也包含进去</p><ul><li>vib（选中小括号内的内容）</li><li>viB（选中大括号内的内容）</li><li>vi&quot;（选中双引号内的内容）</li><li>vi&#39;（选中单引号内的内容）</li><li>vi&lt;（选中尖括号内的内容）</li></ul><h3 id="_3-6-撤回、查找、替换" tabindex="-1">3.6 撤回、查找、替换 <a class="header-anchor" href="#_3-6-撤回、查找、替换" aria-label="Permalink to &quot;3.6 撤回、查找、替换&quot;">​</a></h3><ul><li>u： 撤回上次操作(效果跟 command + z 效果一样)</li><li>/|?xxx：表示在整篇文档中搜索匹配xxx的字符串, / 表示向下查找, ? 表示向上查找.其中xxx可以是正规表达式。查找到以后, 再输入 n 查找下一个匹配处, 输入 N 反方向查找.</li><li>:%s/original/replacement：检索第一个 “original” 字符串并将其替换成 “replacement”</li><li>:%s/original/replacement/g： 检索并将所有的 “original” 替换为 “replacement”</li><li>:%s/original/replacement/gc：检索出所有的 “original” 字符串，但在替换成 “replacement” 前，先询问是否替换</li></ul>',58),t=[r];function n(h,d,c,p,m,s){return i(),l("div",null,t)}const b=a(o,[["render",n]]);export{_ as __pageData,b as default};
